parameters.query:
SELECT id, tipo_problema, keywords, procedimiento 
FROM troubleshooting_hardware 
ORDER BY id;

parameters.jsCode:
const rows = $input.all();
const descripcion = $('When Executed by Another Workflow').first().json.descripcion;

const catalogo = rows.map(r => 
  `ID: ${r.json.id} | Problema: ${r.json.tipo_problema} | Keywords: ${r.json.keywords}`
).join('\n');

return [{ json: { catalogo, descripcion } }];

const idElegido = parseInt($input.first().json.text.trim());
const rows = $('Execute a SQL query').all();

if (idElegido === 0) {
  return [{ json: { 
    procedimiento: 'No encontré un flujo de hardware que coincida con este problema. Por favor describe mejor el equipo o síntoma.' ,
    tipo_problema: null,
    media_refs: []
  }}];
}

const match = rows.find(r => r.json.id === idElegido);

if (!match) {
  return [{ json: { 
    procedimiento: 'No encontré un flujo para este problema.',
    tipo_problema: null,
    media_refs: []
  }}];
}

const procedimiento = match.json.procedimiento;
const tipo_problema = match.json.tipo_problema;

// Extrae todas las referencias multimedia en el orden en que aparecen
const mediaRefs = [];
const regex = /(?:🖼️|📹)\s*((?:Imagen|Video)\s*[\d.]+(?:\s*\/\s*(?:Imagen|Video)\s*[\d.]+)*)/gi;
let m;
while ((m = regex.exec(procedimiento)) !== null) {
  // Maneja referencias múltiples en un paso: "Imagen 17 / Video 19 y 20"
  const partes = m[1].split(/\s*[\/y]\s*/i);
  partes.forEach(p => {
    const ref = p.trim();
    if (ref && !mediaRefs.includes(ref)) mediaRefs.push(ref);
  });
}

return [{ json: { procedimiento, tipo_problema, media_refs: mediaRefs } }];
